const raw = $input.all().map(i => i.json);
const businesses = raw.length === 1 && Array.isArray(raw[0]) ? raw[0] : raw;
const results = [];
for (const biz of businesses) {
  const id = biz.business_id || biz.name;
  if (!id || id === '_template') continue;
  results.push({ json: { businessId: id, businessName: biz.name || id, businessPath: 'memory-bank/businesses/' + id, repo_name: biz.repo_name || id } });
}
if (results.length === 0) return [{ json: { _skip: true, _reason: 'No active businesses found' } }];
return results;

// Decode the base64 content from GitHub API response
const rawContent = Buffer.from($('Step 1 - Read Content Report').first().json.content, 'base64').toString('utf-8');

// Split content by the ---PIECE--- markers used by Content Agent
const pieces = rawContent.split('---PIECE---').filter(p => p.trim().length > 0);

const today = $now.toFormat('yyyy-MM-dd');
const blogPosts = [];

for (const piece of pieces) {
  const trimmed = piece.trim();

  // Only process blog type pieces (skip reels)
  const typeMatch = trimmed.match(/type:\s*(blog|reel)/i);
  if (typeMatch && typeMatch[1].toLowerCase() === 'reel') {
    continue; // Skip reel scripts
  }

  let title = '';
  let excerpt = '';
  let tags = ['auto repair', 'shop management'];
  let bodyContent = trimmed;

  // Check if piece already has frontmatter
  const frontmatterMatch = trimmed.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
  if (frontmatterMatch) {
    const fm = frontmatterMatch[1];
    bodyContent = frontmatterMatch[2].trim();

    const titleMatch = fm.match(/title:\s*["']?(.+?)["']?\s*$/m);
    if (titleMatch) title = titleMatch[1];

    const descMatch = fm.match(/description:\s*["']?(.+?)["']?\s*$/m);
    if (descMatch) excerpt = descMatch[1];

    const excerptMatch = fm.match(/excerpt:\s*["']?(.+?)["']?\s*$/m);
    if (excerptMatch) excerpt = excerptMatch[1];

    const tagsMatch = fm.match(/tags:\s*\[(.+?)\]/m);
    if (tagsMatch) {
      tags = tagsMatch[1].split(',').map(t => t.trim().replace(/["']/g, ''));
    }
  } else {
    // Extract title from first markdown heading
    const headingMatch = trimmed.match(/^#\s+(.+)$/m);
    if (headingMatch) {
      title = headingMatch[1].trim();
      bodyContent = trimmed.replace(/^#\s+.+$/m, '').trim();
    }

    // Try to extract title from metadata line
    const metaTitleMatch = trimmed.match(/title:\s*["']?(.+?)["']?\s*$/m);
    if (metaTitleMatch && !title) {
      title = metaTitleMatch[1];
    }
  }

  // Skip pieces without a title (not a blog post)
  if (!title) continue;

  // Generate excerpt from first paragraph if not found
  if (!excerpt) {
    const firstParagraph = bodyContent.split('\n\n').find(p => p.trim().length > 20 && !p.startsWith('#') && !p.startsWith('type:') && !p.startsWith('tags:'));
    if (firstParagraph) {
      excerpt = firstParagraph.trim().substring(0, 160).replace(/\n/g, ' ');
      if (excerpt.length >= 160) excerpt += '...';
    } else {
      excerpt = title;
    }
  }

  // Strip metadata lines from body content
  bodyContent = bodyContent
    .replace(/^type:\s*.+$/gm, '')
    .replace(/^tags:\s*.+$/gm, '')
    .replace(/^title:\s*.+$/gm, '')
    .replace(/^description:\s*.+$/gm, '')
    .replace(/^excerpt:\s*.+$/gm, '')
    .replace(/^author:\s*.+$/gm, '')
    .replace(/^date:\s*.+$/gm, '')
    .trim();

  // Generate URL-friendly slug from title
  const slug = title
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 80);

  // Build proper gray-matter frontmatter
  const tagsFormatted = JSON.stringify(tags);
  const bizName = $('Split Into Businesses').first().json.businessName || 'BayFlow';
  const fullContent = `---\ntitle: "${title.replace(/"/g, '\\"')}"\nexcerpt: "${excerpt.replace(/"/g, '\\"')}"\ndate: "${today}"\nauthor: "${bizName} Team"\ntags: ${tagsFormatted}\n---\n\n${bodyContent}`;

  blogPosts.push({
    slug,
    title,
    content_with_frontmatter: fullContent
  });
}

if (blogPosts.length === 0) {
  return [{ json: { noPosts: true, message: 'No blog posts found in content report' } }];
}

return blogPosts.map(post => ({ json: post }));

const slug = $json.slug;
const title = $json.title;
const content = $json.content_with_frontmatter;
const contentB64 = Buffer.from(content, 'utf-8').toString('base64');

// Check if the file already exists (has a sha)
const existingFile = $('Step 3a - Check If File Exists').first().json;
const sha = existingFile.sha || null;

const payload = {
  message: `Publish blog post: ${title}`,
  content: contentB64
};

// If file exists, include sha for update
if (sha) {
  payload.sha = sha;
}

return [{
  json: {
    slug,
    title,
    payload: JSON.stringify(payload)
  }
}];

const slug = $('Step 3b - Prepare Commit Payload').first().json.slug;
const siteUrl = $('Split Into Businesses').first().json.site_url || 'https://bayflow.com';
const blogUrl = `${siteUrl}/blog/${slug}`;

return [{
  json: {
    slug,
    blogUrl,
    indexingPayload: JSON.stringify({
      url: blogUrl,
      type: 'URL_UPDATED'
    })
  }
}];

// Collect results from all processed blog posts
const items = $input.all();
const today = $now.toFormat('yyyy-MM-dd');

const publishedPosts = [];
for (const item of items) {
  publishedPosts.push({
    slug: item.json.slug || 'unknown',
    url: item.json.blogUrl || 'unknown',
    indexingSubmitted: !item.json.error
  });
}

const report = `# Content Publisher Report - ${today}\n\n## Status: SUCCESS\n\n## Published Blog Posts\n\n${publishedPosts.map((p, i) => `### ${i + 1}. ${p.slug}\n- **URL**: ${p.url}\n- **Committed to**: src/content/blog/${p.slug}.md\n- **Google Indexing**: ${p.indexingSubmitted ? 'Submitted' : 'Skipped (API not configured)'}\n`).join('\n')}\n\n## Summary\n- **Total posts published**: ${publishedPosts.length}\n- **Target repo**: Sluice-Organization/${$('Split Into Businesses').first().json.repo_name}\n- **Vercel auto-deploy**: Triggered by commit\n- **Timestamp**: ${new Date().toISOString()}\n`;

const reportB64 = Buffer.from(report, 'utf-8').toString('base64');

return [{
  json: {
    report,
    reportPayload: JSON.stringify({
      message: `Content Publisher report - ${today}`,
      content: reportB64
    })
  }
}];
